<template>
    <el-menu
      :default-active="'/index'"
      router
      mode="horizontal"
      background-color="#545c64"
      text-color="#fff"
      active-text-color="red">
      <el-menu-item v-for="(item,i) in navList" :key="i" :index="item.name">
        <b>{{ item.navItem }}</b>
      </el-menu-item>
      <a href="#nowhere" style="color: white;float: right;padding: 20px;">更多功能</a>
      <i class="el-icon-menu" style="float:right;font-size: 30px;color: #222;padding-top: 17px"></i>
    </el-menu>
</template>

<script>
export default {
  name: 'NavMenu',
  data () {
    return {
      navList: [
        {name: '/index', navItem: '首页'},
        {name: '/note', navItem: 'vue组件库'},
        {name: '/admin', navItem: '个人中心'}
      ]
    }
  }
}
</script>

<style scoped>
  a{
    text-decoration: none;
  }

  span {
    pointer-events: none;
  }
</style>



