import Vue from 'vue'
import Router from 'vue-router'
import Home from '@/components/Home'
import Note from '@/components/Note'
import Admin from '@/components/Admin'
import AppIndex from '../components/home/AppIndex'

Vue.use(Router)

export default new Router({
  routes: [
    {
      path: '/',
      name: 'Home',
      component: Home,
      // Home页面并不需要被访问
      redirect: '/index',
      children: [
        {
          path: '/index',
          name: 'AppIndex',
          component: AppIndex
        },
        {
          path: '/note',
          name: 'Note',
          component: Note
        },
        {
          path: '/admin',
          name: 'Admin',
          component: Admin
        }
      ]
    }
  ]
})



