<!--  -->
<template>
<div class="all_container">
    <div class="nav">
        <NavMenu></NavMenu>
    </div>
    <div class="row">
        <div class="leftcolumn">
            <!-- 这里用来盛放中间 左侧栏目内容 -->
            <router-view/>
        </div>
        <div class="rightcolumn">
            <RightColumn></RightColumn>
        </div>
    </div>
    <div class="footer">
        <Footer></Footer>
    </div>
  </div>
</template>

<script>
// 导入的其他文件 例如：import moduleName from 'modulePath';
import NavMenu from './common/NavMenu'
import Footer from './home/Footer'
import RightColumn from './common/RightColumn'
export default {
  // import所引入的组件注册
  components: {
    NavMenu,
    RightColumn,
    Footer
  },

  name: '',
  data () {
    return {
      msg: '属性'
    }
  },

  // 监听属性
  computed: {

  },

  // 监控data中的数据变化
  watch: {

  },

  // 方法集合
  methods: {

  },

  // 生命周期 - 组件实例刚被创建
  beforeCreate () {

  },
  // 创建完成 访问当前this实例
  created () {

  },
  // 挂载之前
  beforeMount () {

  },
  // 挂载完成 访问DOM元素
  mounted () {

  },
  // 更新之前
  beforeUpdate () {

  },
  // 更新之后
  updated () {

  },
  // for keep-alive 缓存功能，组件被激活时调用
  activated () {

  },
  // for keep-alive 组件被移除时调用
  deactivated () {

  },
  // 组件销毁之前调用
  beforeDestroy () {

  },
  // 组件销毁之后调用
  destroyed () {

  }
}
</script>
<style scoped src="../../static/css/home.css">

</style>



