<!-- vueelement -->
<template>
<div class='footer'>
  <h3 style="text-align:left;color:red;">Vue组件库整理-更新中...</h3>
      <Collapse v-for="item in vueinfo"  :key="item.id" class="content">
      <div class="card" style="text-align:left;">
        <Panel>
          <span> {{ item.id }} - {{ item.name }}</span>
          <div slot="content">
            <span class="linkurl" style="color:blue;" @click="See(item.address)">地址:{{ item.address }}</span>
            <p>描述:{{ item.desc }}</p>
            <p>优点:{{ item.advantage }}</p>
            <p>缺点:{{ item.disadvantage }}</p>
          </div>
        </Panel>
        </div>
      </Collapse>
</div>
</template>

<script>
// 导入的其他文件 例如：import moduleName from 'modulePath';
export default {
  // import所引入的组件注册
  components: {

  },

  name: '',
  data () {
    return {
      msg: '属性',
      vueinfo: []
    }
  },

  // 监听属性
  computed: {

  },

  // 监控data中的数据变化
  watch: {

  },

  // 方法集合
  methods: {
    getVueElementJson () {
      const url = '../../../static/json/vueelement.json'
      // alert('进入就调用方法: getMainLeftJson()  url=' + url)
      this.$axios({
        url: url
      }).then((res) => {
        var obj = JSON.parse(JSON.stringify(res.data))
        this.vueinfo = obj.VueElement
      }).catch((err) => {
        console.log(err)
        alert(err)
      })
    },
    See (e) {
      // alert(e)
      window.location.href = e
    }
  },

  // 生命周期 - 组件实例刚被创建
  beforeCreate () {

  },
  // 创建完成 访问当前this实例
  created () {

  },
  // 挂载之前
  beforeMount () {

  },
  // 挂载完成 访问DOM元素
  mounted () {
    this.getVueElementJson()
  },
  // 更新之前
  beforeUpdate () {

  },
  // 更新之后
  updated () {

  },
  // for keep-alive 缓存功能，组件被激活时调用
  activated () {

  },
  // for keep-alive 组件被移除时调用
  deactivated () {

  },
  // 组件销毁之前调用
  beforeDestroy () {

  },
  // 组件销毁之后调用
  destroyed () {

  }
}
</script>

<style scoped src="../../static/css/home.css">

</style>



