<!--  -->
<template>
<div class=''>
  <h1>{{ name }}</h1>
    <h3 style="text-align:left;color:red;">学习开发进度-更新中...</h3>
    <div class="card" v-for="item in article" :key="item">
        <h4 class="cardTitle">{{item.title}}</h4>
        <h5 class="cardTime">{{item.time}}</h5>
        <div class="fakeimg">
            <viewer :images="images" style="height: 800px;">
                <el-image style="fit:cover;width:300px;height:300px;" v-for="url in item.imgurl" :key="url" :src="url"></el-image>
            </viewer>
          <br/>
        </div>
        <br/>
        <el-tag style="float: right">
          {{ item.label }}
        </el-tag>

        <div class="block" style="text-align:left;width:90%;">
          <el-timeline>
            <el-timeline-item
              v-for="(item, index) in item.content"
              :key="index"
              :icon="el-icon-more"
              :type="primary">
              <span style="font-size:15px;"><b>{{item}}</b></span>
            </el-timeline-item>
          </el-timeline>
        </div>
    </div>
</div>
</template>

<script>

// 导入的其他文件 例如：import moduleName from 'modulePath';
export default {
  // import所引入的组件注册
  components: {

  },

  name: 'MainLeft',
  data () {
    return {
      msg: '属性',
      article: []
    }
  },

  // 监听属性
  computed: {

  },

  // 监控data中的数据变化
  watch: {

  },

  // 方法集合
  methods: {
    // 获取MainLeftJson数据
    getMainLeftJson () {
      const url = '../../../static/json/mainleft.json'
      // alert('进入就调用方法: getMainLeftJson()  url=' + url)
      this.$axios({
        url: url
      }).then((res) => {
        // alert json串
        var jsonStr = JSON.stringify(res.data)
        // alert(jsonStr)
        var obj = JSON.parse(jsonStr)
        this.article = obj.article
      }).catch((err) => {
        console.log(err)
        alert(err)
      })
    }
  },

  // 生命周期 - 组件实例刚被创建
  beforeCreate () {

  },
  // 创建完成 访问当前this实例
  created () {

  },
  // 挂载之前
  beforeMount () {

  },
  // 挂载完成 访问DOM元素
  mounted () {
    this.getMainLeftJson()
  },
  // 更新之前
  beforeUpdate () {

  },
  // 更新之后
  updated () {

  },
  // for keep-alive 缓存功能，组件被激活时调用
  activated () {

  },
  // for keep-alive 组件被移除时调用
  deactivated () {

  },
  // 组件销毁之前调用
  beforeDestroy () {

  },
  // 组件销毁之后调用
  destroyed () {

  }
}
</script>
<style scoped src="../../../static/css/home.css">

</style>



